                val current_xor = prefix_xor[i] xor prefix_xor[m]
                val current_max = max(dp[m][j - 1], current_xor)
                if (current_max < dp[i][j]) {
                    dp[i][j] = current_max
                }
            }
        }
    }
    return dp[n][k.toInt()]
}
